options.getOption:
const s = context.panel.data.series[0];
const isDark = context.grafana.theme.isDark;
const textColor = isDark ? '#ccc' : '#333';
let count = 0, maxMs = 0, minMs = 0;
if (s && s.fields) {
  for (const f of s.fields) {
    const n = (f.name || '').toLowerCase();
    if (n.includes('count')) count = f.values[0] || 0;
    else if (n === 'max' || n.includes('max')) maxMs = f.values[0] || 0;
    else if (n === 'min' || n.includes('min')) minMs = f.values[0] || 0;
  }
}
const spreadMin = (maxMs - minMs) / 60000;
const throughput = spreadMin > 0 ? (count / spreadMin).toFixed(1) : '0';
return {
  graphic: { elements: [
    { type: 'text', left: 'center', top: '30%', style: {
      text: throughput, fontSize: 36, fontWeight: 'bold',
      fill: Number(throughput) > 10 ? '#73BF69' : Number(throughput) > 5 ? '#FADE2A' : '#F2495C'
    }},
    { type: 'text', left: 'center', top: '65%', style: {
      text: 'VMs / min', fontSize: 14, fill: textColor
    }}
  ]}
};

const s = context.panel.data.series[0];
const isDark = context.grafana.theme.isDark;
const textColor = isDark ? '#ccc' : '#333';
const percentile = context.grafana.replaceVariables('$latencyPercentile') || 'P99';

if (!s || !s.fields || s.fields.length < 2) {
  return { title: { text: 'No VMI latency data', left: 'center', top: 'center', textStyle: { color: textColor } } };
}

let nameField = null, valueField = null;
for (const f of s.fields) {
  if (f.type === 'string' || (f.name || '').toLowerCase().includes('quantile')) nameField = f;
  else if (f.type === 'number' || (f.name || '').toLowerCase().includes('average')) valueField = f;
}
if (!nameField || !valueField) {
  return { title: { text: 'No data fields', left: 'center', top: 'center', textStyle: { color: textColor } } };
}

const phaseOrder = ['VMICreated','VMIPending','VMIScheduling','VMIScheduled','PodPodScheduled','PodCreated','PodInitialized','PodContainersReady','VMIRunning','VMReady'];
const raw = {};
for (let i = 0; i < nameField.values.length; i++) {
  raw[nameField.values[i]] = (valueField.values[i] || 0) / 1000;
}
const phases = phaseOrder.filter(p => raw[p] !== undefined);
const cumulative = phases.map(p => raw[p]);

const deltas = [];
for (let i = 0; i < cumulative.length; i++) {
  if (i === 0) deltas.push(cumulative[0]);
  else deltas.push(Math.max(0, cumulative[i] - cumulative[i - 1]));
}

const base = cumulative.map((c, i) => i === 0 ? 0 : cumulative[i - 1]);

const colors = ['#5470c6','#91cc75','#fac858','#ee6666','#73c0de','#3ba272','#fc8452','#9a60b4','#ea7ccc','#5794F2'];

return {
  tooltip: {
    trigger: 'axis',
    formatter: function(params) {
      const phase = params[0].name;
      const p0 = params.find(p => p.seriesName === 'base');
      const p1 = params.find(p => p.seriesName === 'Phase Duration');
      const cum = p0 && p1 ? (p0.value + p1.value) : 0;
      const delta = p1 ? p1.value : 0;
      return '<b>' + phase + '</b><br/>Cumulative: ' + cum.toFixed(1) + ' s<br/>Phase duration: ' + delta.toFixed(1) + ' s';
    }
  },
  grid: { left: 60, right: 30, top: 30, bottom: 80 },
  xAxis: { type: 'category', data: phases, axisLabel: { color: textColor, rotate: 35, fontSize: 11 } },
  yAxis: { type: 'value', name: percentile + ' Latency (s)', nameTextStyle: { color: textColor }, axisLabel: { color: textColor },
    splitLine: { lineStyle: { color: isDark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.08)' } } },
  series: [
    {
      name: 'base',
      type: 'bar',
      stack: 'waterfall',
      data: base,
      itemStyle: { color: 'transparent' },
      emphasis: { itemStyle: { color: 'transparent' } }
    },
    {
      name: 'Phase Duration',
      type: 'bar',
      stack: 'waterfall',
      data: deltas.map((d, i) => ({ value: d, itemStyle: { color: colors[i % colors.length] } })),
      label: { show: true, position: 'top', formatter: function(p) { return p.value.toFixed(1) + 's'; },
        color: textColor, fontSize: 11 }
    }
  ]
};
